from flask import Flask
from prometheus_client import Summary, Histogram, Gauge

app = Flask(__name__)

# Define a summary metric to track request count and response time
request_summary = Summary('requests', 'Number of requests and their response times')

# Define a histogram metric to track the latency of requests
latency_histogram = Histogram('latency', 'Request latency')

# Define a gauge metric to track the number of active users
active_users = Gauge('active_users', 'Number of active users')

@app.route('/metrics')
def metrics():
    return request_summary.to_prometheus_client_response() + \
           latency_histogram.to_prometheus_client_response() + \
           active_users.to_prometheus_client_response()